class Solution {
public:
    void rotate(vector<int>& nums, int k) {
        int n = nums.size();
        int rotate = k % n;
        if (rotate == 0 || n == 0)
            return;

        int var_swap = nums[n - rotate];
        int* arr = new int[rotate]; 

        for(int i = 0; i < rotate; i++){
            arr[i] = nums[n - rotate + i];
        }

        for (int x = 0; x < rotate; x++){
            for(int i = x; i < n; i++){
                int temp = nums[i];
                nums[i] = var_swap;
                var_swap = temp;
            }
        } 

        for (int i = 0; i < rotate; i++){
            nums[i] = arr[i];
        }

    }
};

class Solution
{
	public: void rotate(vector<int> &nums, int k)
	{
		int n = nums.size();
		int rotate = k % n;
		if (rotate == 0 || n == 0)
			return;

		int var_swap = nums[0];
		int tmp = 0;
		int rotated = 0;
		int start = 0;
		int curr = 0;

		while (rotated < n)
		{
			do { 	
                tmp = nums[(curr + rotate) %n];
				nums[(curr + rotate) % n] = var_swap;
				var_swap = tmp;
				curr = (curr + rotate) % n;
				rotated++;
			} while (curr != start);
			start++;
			curr = start;
			var_swap = nums[curr];
		}

	}

};
